    long i,j;

    while(scanf("%ld %ld",&i,&j)==2) {
        long start = i<j ? i:j;
        long end = i>j ? i:j;

        long maxCycle = 0;

        for(long k=start;k<=end;k++) {
            long length = cycleLength(k);
            if(length>maxCycle)
                maxCycle = length;
        }

