lines <- readLines("stdin")

M <- 0
N <- 0
grid <- NULL

create <- function(m, n) {
  M <<- m
  N <<- n
  grid <<- matrix("O", nrow = N, ncol = M)
}

clear_table <- function() {
  grid[,] <<- "O"
}

color_pixel <- function(x, y, c) {
  if (x >= 1 && x <= M && y >= 1 && y <= N) {
    grid[y, x] <<- c
  }
}

vertical <- function(x, y1, y2, c) {
  if (x < 1 || x > M) return()
  if (y1 > y2) {
    temp <- y1; y1 <- y2; y2 <- temp
  }
  for (y in y1:y2) {
    if (y >= 1 && y <= N)
      grid[y, x] <<- c
  }
}

horizontal <- function(x1, x2, y, c) {
  if (y < 1 || y > N) return()
  if (x1 > x2) {
    temp <- x1; x1 <- x2; x2 <- temp
  }
  for (x in x1:x2) {
    if (x >= 1 && x <= M)
      grid[y, x] <<- c
  }
}

rectangle_fill <- function(x1, y1, x2, y2, c) {
  if (x1 > x2) {
    temp <- x1; x1 <- x2; x2 <- temp
  }
  if (y1 > y2) {
    temp <- y1; y1 <- y2; y2 <- temp
  }
  for (y in y1:y2) {
    for (x in x1:x2) {
      if (x >= 1 && x <= M && y >= 1 && y <= N)
        grid[y, x] <<- c
    }
  }
}

flood_fill <- function(x, y, c) {
  if (x < 1 || x > M || y < 1 || y > N) return()

  old <- grid[y, x]
  if (old == c) return()

  qy <- c(y)
  qx <- c(x)
  grid[y, x] <<- c

  while (length(qy) > 0) {
    cy <- qy[1]
    cx <- qx[1]
    qy <- qy[-1]
    qx <- qx[-1]

    dirs <- list(c(-1,0), c(1,0), c(0,-1), c(0,1))

    for (d in dirs) {
      ny <- cy + d[1]
      nx <- cx + d[2]

      if (ny >= 1 && ny <= N &&
          nx >= 1 && nx <= M &&
          grid[ny, nx] == old) {
        grid[ny, nx] <<- c
        qy <- c(qy, ny)
        qx <- c(qx, nx)
      }
    }
  }
}

