	mut lines := os.get_raw_lines()
	mut index := 0

	for {
		if index >= lines.len {
			break
		}

		n := lines[index].int()
		index++

		if n==0 {
			break
		}

		mut expenses := []i64{}
		mut total := i64(0)

		for _ in 0 .. n {
			s := lines[index].trim_space()
			index++

			parts := s.split(".")
			dollars := parts[0].i64()
			cents := parts[1].i64()

			value := dollars*100+cents
			expenses << value
			total += value
		}

		avg := total /n

		mut give := i64(0)
		mut take := i64(0)

		for e in expenses {
			if e > avg {
				give += e - avg
			} else {
				take += avg - e
			}
		}

		result := if give > take {give} else {take}

		println("\$${f64(result)/100:.2f}")
	}
}

import os
import math
import strconv

fn main() {
	lines := os.get_lines()

	for line in lines {
		if line.trim_space() == '' { continue }

		parts := line.split(' ')
		if parts.len == 0 { continue }

		n := strconv.atoi(parts[0]) or { continue }

		if n == 1 {
			println('Jolly')
			continue
		}

		mut nums := []int{cap: n}

		for i in 1 .. parts.len {
			if parts[i] != '' {
				nums << strconv.atoi(parts[i]) or { 0 }
			}
		}

		mut found_diffs := []bool { len: n,init: false}
		mut jolly := true

		for i in 0 .. (n-1) {
			diff := int(math.abs(nums[i]-nums[i+1]))

			if diff >= 1 && diff < n && !found_diffs[diff] {
				found_diffs[diff] = true
			} else {
				jolly = false
				break
			}
		}

		if jolly {
			println('Jolly')
		} else {
			println('Not jolly')
		}
	}
}
